"use strict";parserFactory.register("toctruyen.net",()=>new ToctruyenParser);class ToctruyenParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=new RegExp("/truyen/.+"),r=e.baseURI.match(t)?.[0].slice(8),n=r.split("/")[0];return(await HttpClient.fetchJson("https://toctruyen.net/content/subitems?pid="+n)).json.data.e.map(e=>({sourceUrl:e[3],title:e[2]})).reverse()}findContent(e){return e.querySelector(".novel-reading-content .novel-reading-viewport")}findChapterTitle(e){return e.querySelector(".novel-reading-header h2")}extractTitleImpl(e){return e.querySelector(".novel-header h1").textContent}extractSubject(e){return[...e.querySelectorAll(".detail-genres a")].map(e=>e.textContent.trim()).join(", ")}extractDescription(e){return e.querySelector("#description").textContent}findCoverImageUrl(e){return e.querySelector(".novel-thumb").dataset.original}}